import{_ as e,c as i,o as a,a as l}from"./app.277c03ee.js";const f='{"title":"CHANGELOG","description":"","frontmatter":{},"headers":[{"level":2,"title":"2022-02-08","slug":"_2022-02-08"},{"level":2,"title":"2022-01-14","slug":"_2022-01-14"},{"level":2,"title":"2022-01-10","slug":"_2022-01-10"},{"level":2,"title":"2021-12-17","slug":"_2021-12-17"},{"level":2,"title":"2021-12-14","slug":"_2021-12-14"},{"level":2,"title":"2021-12-08","slug":"_2021-12-08"}],"relativePath":"changelog.md","lastUpdated":1644325109437}',t={},o=l('<h1 id="changelog"><a class="header-anchor" href="#changelog" aria-hidden="true">#</a> CHANGELOG</h1><h2 id="_2022-02-08"><a class="header-anchor" href="#_2022-02-08" aria-hidden="true">#</a> 2022-02-08</h2><ul><li>mob2: New frame matrix system. Now walls can mix designed nails with auto-generated nails for columns without nails in the draw.</li><li>mob2: Milling polygons now keeps the milling tool down.</li><li>IFC PS can be now downloaded or uploaded as .json files.</li><li>Machine setup can be now downloaded or uploaded as .json files.</li><li>Project documentation can be added now as a PDF or as a raw text.</li><li>Mouse scrolling improvements in PDF and IFC view.</li></ul><h2 id="_2022-01-14"><a class="header-anchor" href="#_2022-01-14" aria-hidden="true">#</a> 2022-01-14</h2><ul><li>Production Overview (beta2): loose batch picker, autoscroll to <em>now</em>, custom batch expected time, sticky left column, week startdate fix, fixed bugs.</li><li>Project Overview.</li><li>Improved status update on URL direct reload.</li><li>Fixed hidden phases dialog.</li><li>JJS Files (beta): Now, the users can upload JJS files in <a href="http://produuz.it" target="_blank" rel="noopener noreferrer">produuz.it</a> as an alternative from IFC files.</li><li>mob2: Added new feature for lockout areas.</li><li>mob2: Improved performance and reliability.</li><li>btl: Improved performance and reliability.</li></ul><h2 id="_2022-01-10"><a class="header-anchor" href="#_2022-01-10" aria-hidden="true">#</a> 2022-01-10</h2><ul><li>Improved reliability in panel count matrix.</li><li>Fixed a bug in report settings. Some settins were not correctly stored on clone/edit.</li><li>Fixed RFID button in viewer.</li><li>Company Production Overview (beta).</li><li>Full plates selector in plates reports.</li><li>Android: First release.</li><li>mob2: Added support for triangular panels.</li><li>mob2: Auto-remove duplicate milling operations.</li><li>mob2: Improved performance and reliability.</li><li>btl: Improved performance and reliability.</li></ul><h2 id="_2021-12-17"><a class="header-anchor" href="#_2021-12-17" aria-hidden="true">#</a> 2021-12-17</h2><ul><li>ardis: Fixed an issue for Ardis csv generation.</li><li>ardis: Swith Width and Lenth for Ardis csv export.</li><li>mob2: Shift feature now based en machine Zeros.</li><li>mob2: Inside height is count now from the lowest level in frame parts.</li><li>mob2: Added a new feature for layers generation. Now the user can select between 3 options for generate the layers that corresponds to a certain machine, if the operations coordinates are above machine sizes:</li><li>Generate anyway: ignore the machine sizes, and generate the operations.</li><li>Do not generate the layer: if any operations is above machine sizes, the layer will not be generated.</li><li>Trim operations up to max size: the operations that exceeds machine sizes, will be trimmed up to the machine limit.</li><li>mob2: Added a new feature for twin nailings patterns. Now the user can select between the regular pattern, or a new one optimized for large panels.</li></ul><h2 id="_2021-12-14"><a class="header-anchor" href="#_2021-12-14" aria-hidden="true">#</a> 2021-12-14</h2><ul><li>Improved operations status indications and disabled actions.</li><li>Solved several bugs in operations (generate_designs, detect_details, prepare_viewer).</li><li>Operation detect_details now has checked boxes by default since most users forget to check it.</li><li>IFC PS clone feature.</li><li>Change Stations men\xFA upgrade.</li><li>mob2+mob1 files: Glueing and bricks bugs fixed.</li></ul><h2 id="_2021-12-08"><a class="header-anchor" href="#_2021-12-08" aria-hidden="true">#</a> 2021-12-08</h2><ul><li>New file versioning in uploads. This solves some updating bugs.</li><li>New file status indicators (see: <a href="https://docs.produuz.it/operations.html#table-of-uploaded-files" target="_blank" rel="noopener noreferrer">https://docs.produuz.it/operations.html#table-of-uploaded-files</a>)</li><li>mob2+mob1 files: Spiral plate nailing for single nailing.</li><li>mob2+mob1 files: Frame nailing matrix fix for proper studs selection.</li></ul>',13),r=[o];function n(s,d,c,h,u,p){return a(),i("div",null,r)}var g=e(t,[["render",n]]);export{f as __pageData,g as default};
